SELECT s.sale_id, s.store_id, s.staff_id, s.customer_id, s.sale_date, s.total_amount, s.discount_amount, s.payment_method, s.source, s.is_refunded AS refunded, st.name AS store_name, sf.name AS staff_name, c.name AS customer_name FROM sales s JOIN stores st ON s.store_id = st.store_id LEFT JOIN staff sf ON s.staff_id = sf.staff_id LEFT JOIN customers c ON s.customer_id = c.customer_id
AND s.store_id = #{storeId} AND CAST(s.sale_date AS DATE) >= #{startDate} AND CAST(s.sale_date AS DATE) <= #{endDate}
ORDER BY s.sale_id DESC OFFSET #{offset} ROWS FETCH NEXT #{limit} ROWS ONLY

SELECT COUNT(*) FROM sales s

    AND s.store_id = #{storeId}
    AND CAST(s.sale_date AS DATE) >= #{startDate}
    AND CAST(s.sale_date AS DATE) <= #{endDate}
